noncompliant:
for (int i = 0; i < GetCount(); i++) // Noncompliant: method call in stop condition
{
    Console.WriteLine(i);
}

for (int i = 0; i < list.Count; i++) // Noncompliant: property access in stop condition
{
    list.Add(i); // modifying the collection being iterated
}

compliant:
int count = GetCount(); // Compliant: store invariant value before loop
for (int i = 0; i < count; i++)
{
    Console.WriteLine(i);
}

int listCount = list.Count; // Compliant: capture count before loop
for (int i = 0; i < listCount; i++)
{
    Console.WriteLine(list[i]);
}
